}

void
HandleStat(struct yfs_msg *msg, int client_pid)
{
    (void) client_pid;
    /* TODO: Implement Stat */
    msg->size = 0;
}

void
HandleShutdown(struct yfs_msg *msg, int client_pid)
{
    (void) client_pid;
    /* Flush all caches */
    FlushCaches();
    msg->size = 0;
}

void
HandleSync(struct yfs_msg *msg, int client_pid)
{
    (void) client_pid;
    /* Flush all caches */
    FlushCaches();
    msg->size = 0;
}

void
HandleMessage(struct yfs_msg *msg, int client_pid)
{
    switch (msg->op) {
    case OP_CREATE:
        HandleCreate(msg, client_pid);
        break;
    case OP_READ:
        HandleRead(msg, client_pid);
        break;
    case OP_WRITE:
        HandleWrite(msg, client_pid);
        break;
    case OP_CLOSE:
        HandleClose(msg, client_pid);
        break;
    case OP_SEEK:
        HandleSeek(msg, client_pid);
        break;
    case OP_MKDIR:
        HandleMkDir(msg, client_pid);
        break;
    case OP_RMDIR:
        HandleRmDir(msg, client_pid);
        break;
    case OP_UNLINK:
        HandleUnlink(msg, client_pid);
        break;
    case OP_STAT:
        HandleStat(msg, client_pid);
        break;
    case OP_SHUTDOWN:
        HandleShutdown(msg, client_pid);
        break;
    case OP_SYNC:
        HandleSync(msg, client_pid);
        break;
    default:
        TtyPrintf(1, "YFS: Unknown operation %d\n", msg->op);
        msg->size = -1;
        break;
    }
}

/* ========================================================================
 * Main YFS Server Loop
 * ======================================================================== */

int
main()
{
    int status;
    struct yfs_msg msg;
    int pid;

    TtyPrintf(1, "YFS: Starting file system server\n");

    /* Initialize file system */
    if (InitFileSystem() < 0) {
        TtyPrintf(1, "YFS: Failed to initialize file system\n");
        Exit(-1);
    }

    /* Register as FILE_SERVER */
    status = Register(FILE_SERVER);
    if (status < 0) {
        TtyPrintf(1, "YFS: Failed to register as FILE_SERVER\n");
        Exit(-1);
    }

    TtyPrintf(1, "YFS: Registered as FILE_SERVER\n");

    /* Main message loop */
    while (1) {
        /* Wait for incoming message */
        pid = Receive((void *)&msg);
        if (pid < 0) {
            TtyPrintf(1, "YFS: Receive error: %d\n", pid);
            continue;
        }

        /* Handle the message */
        HandleMessage(&msg, pid);

        /* Send reply */
        Reply((void *)&msg, pid);
    }

    return 0;
}

/*
 * COMP 421 Lab 3: Yalnix File System Client Library
 *
 * User-level procedures for file system operations via IPC.
 */

#include <comp421/yalnix.h>
#include <comp421/filesystem.h>
#include <comp421/iolib.h>
#include <string.h>

/* ========================================================================
 * Client-side File Descriptor Table
 * ======================================================================== */

#define MAX_FD 16

struct file_desc {
    int inum;           /* Inode number */
    int offset;         /* Current file position */
    int reuse;          /* Reuse count from server */
    int in_use;         /* Whether this FD is open */
};

static struct file_desc fd_table[MAX_FD];
static int current_dir_inum = ROOTINODE;

/* Shared buffer for pathname transfers */
static char pathname_buffer[MAXPATHNAMELEN];
static char read_buffer[8192];  /* Buffer for Read data transfer */

/* ========================================================================
 * Client-side Message Structure (32 bytes fixed)
 * ======================================================================== */

struct yfs_msg {
    int op;             /* Operation type */
    int fd;             /* File descriptor */
    int inum;           /* Inode number */
    int offset;         /* Offset or seek position */
    int size;           /* Size or return value */
    int whence;         /* Seek mode / reuse count / result */
    long path_ptr;      /* Pointer to pathname in client space */
    int path_len;       /* Pathname length */
};

#define OP_OPEN    1
#define OP_CLOSE   2
#define OP_CREATE  3
#define OP_READ    4
#define OP_WRITE   5
#define OP_SEEK    6
#define OP_MKDIR   7
#define OP_RMDIR   8
#define OP_UNLINK  9
#define OP_LINK    10
#define OP_STAT    11
#define OP_CHDIR   12
#define OP_SYNC    13
#define OP_SHUTDOWN 14

/* ========================================================================
 * Helper Functions
 * ======================================================================== */

static int
GetNextFD()
{
    int i;
    for (i = 0; i < MAX_FD; i++) {
        if (!fd_table[i].in_use) {
            fd_table[i].in_use = 1;
            return i;
        }
    }
    return -1;
}

static int
SendRequest(struct yfs_msg *msg, const char *pathname)
{
    int len = 0;

    /* Copy pathname to shared buffer if provided */
    if (pathname) {
        len = strlen(pathname) + 1;
        if (len > MAXPATHNAMELEN) {
            return -1;
        }
        memcpy(pathname_buffer, pathname, len);
        msg->path_ptr = (long)pathname_buffer;
        msg->path_len = len;
    } else {
        msg->path_ptr = 0;
        msg->path_len = 0;
    }

    /* Send message to FILE_SERVER */
    Send((void *)msg, -FILE_SERVER);

    /* Receive reply */
    Receive((void *)msg);

    return msg->size;
}

/* ========================================================================
 * Library Functions
 * ======================================================================== */

int
Open(char *pathname)
{
    struct yfs_msg msg;
    int fd, result;

    if (!pathname) {
        return -1;
    }

    /* Get next available FD */
    fd = GetNextFD();
    if (fd < 0) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_OPEN;
    msg.fd = fd;

    /* Send request to server */
    result = SendRequest(&msg, pathname);
    if (result < 0) {
        fd_table[fd].in_use = 0;
        return -1;
    }

    /* Store FD info */
    fd_table[fd].inum = msg.inum;
    fd_table[fd].offset = 0;
    fd_table[fd].reuse = msg.whence;

    return fd;
}

int
Close(int fd)
{
    struct yfs_msg msg;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_CLOSE;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;

    /* Send to server */
    Send((void *)&msg, -FILE_SERVER);
    Receive((void *)&msg);

    /* Clear FD */
    fd_table[fd].in_use = 0;

    return msg.size;
}

int
Create(char *pathname)
{
    struct yfs_msg msg;
    int fd, result;

    if (!pathname) {
        return -1;
    }

    /* Get next available FD */
    fd = GetNextFD();
    if (fd < 0) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_CREATE;
    msg.fd = fd;

    /* Send request to server */
    result = SendRequest(&msg, pathname);
    if (result < 0) {
        fd_table[fd].in_use = 0;
        return -1;
    }

    /* Store FD info */
    fd_table[fd].inum = msg.inum;
    fd_table[fd].offset = 0;
    fd_table[fd].reuse = msg.whence;

    return fd;
}

int
Read(int fd, void *buf, int nbytes)
{
    struct yfs_msg msg;
    int nread;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use || !buf) {
        return -1;
    }

    if (nbytes < 0) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_READ;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;
    msg.size = nbytes;
    msg.path_ptr = (long)read_buffer;
    msg.path_len = sizeof(read_buffer);

    /* Send to server */
    Send((void *)&msg, -FILE_SERVER);

    /* Receive message */
    Receive((void *)&msg);
    nread = msg.size;

    if (nread > 0 && nread <= nbytes) {
        /* Copy data from read_buffer to user buffer */
        memcpy(buf, read_buffer, nread);
        fd_table[fd].offset += nread;
    }

    return nread;
}

int
Write(int fd, void *buf, int nbytes)
{
    struct yfs_msg msg;
    int nwritten;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use || !buf) {
        return -1;
    }

    if (nbytes < 0) {
        return -1;
    }

    /* Copy data to shared buffer */
    if (nbytes > (int)sizeof(read_buffer)) {
        nbytes = sizeof(read_buffer);
    }
    memcpy(read_buffer, buf, nbytes);

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_WRITE;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;
    msg.size = nbytes;
    msg.path_ptr = (long)read_buffer;
    msg.path_len = nbytes;

    /* Send to server */
    Send((void *)&msg, -FILE_SERVER);

    /* Receive reply */
    Receive((void *)&msg);
    nwritten = msg.size;

    if (nwritten > 0) {
        fd_table[fd].offset += nwritten;
    }

    return nwritten;
}

int
Seek(int fd, int offset, int whence)
{
    struct yfs_msg msg;
    int new_offset;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_SEEK;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = offset;
    msg.whence = whence;
    msg.size = fd_table[fd].offset;

    /* Send to server */
    Send((void *)&msg, -FILE_SERVER);
    Receive((void *)&msg);

    new_offset = msg.size;
    if (new_offset >= 0) {
        fd_table[fd].offset = new_offset;
    }

    return new_offset;
}

int
MkDir(char *pathname)
{
    struct yfs_msg msg;

    if (!pathname) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
