+/*
+ * COMP 421 Lab 3: Yalnix File System Server
+ *
+ * Complete file system server with caching and file operations.
+ */
+
+#include <comp421/yalnix.h>
+#include <comp421/hardware.h>
+#include <comp421/filesystem.h>
+#include <string.h>
+#include <stdio.h>
+
+/* Message structure for IPC (32 bytes fixed) */
+struct yfs_msg {
+    int op;             /* Operation type */
+    int fd;             /* File descriptor */
+    int inum;           /* Inode number */
+    int offset;         /* Offset or seek position */
+    int size;           /* Size or return value */
+    int whence;         /* Seek mode / reuse count */
+    long path_ptr;      /* Pointer to pathname in client */
+    int path_len;       /* Pathname length */
+};
