+{
+    int i;
+
+    /* Flush inodes */
+    for (i = 0; i < inode_cache_count; i++) {
+        if (inode_cache[i].dirty && inode_cache[i].inum >= 0) {
+            int inum = inode_cache[i].inum;
+            int inodes_per_block = BLOCKSIZE / INODESIZE;
+            int block_num = inode_start_block + (inum / inodes_per_block);
+            int offset = (inum % inodes_per_block) * INODESIZE;
+
+            /* Read block, update inode, write back */
+            if (ReadSector(block_num, (void *)disk_buffer) < 0) {
+                return -1;
+            }
+            memcpy(disk_buffer + offset, &inode_cache[i].inode, INODESIZE);
+            if (WriteSector(block_num, (void *)disk_buffer) < 0) {
+                return -1;
+            }
+            inode_cache[i].dirty = 0;
+        }
+    }
+
+    /* Flush blocks */
+    for (i = 0; i < block_cache_count; i++) {
+        if (block_cache[i].dirty && block_cache[i].block_num >= 0) {
+            if (WriteSector(block_cache[i].block_num, (void *)block_cache[i].data) < 0) {
+                return -1;
+            }
+            block_cache[i].dirty = 0;
+        }
+    }
+
+    return 0;
+}
