+    }
+
+    /* Make a copy for strtok */
+    buf = pathname_buffer;
+    strncpy(buf, pathname, MAXPATHNAMELEN - 1);
+    buf[MAXPATHNAMELEN - 1] = '\0';
+
+    /* Split by '/' */
+    token = strtok_r(buf, "/", &saveptr);
+    while (token && count < max_components) {
+        if (strlen(token) > 0 && strcmp(token, ".") != 0) {
+            components[count++] = token;
+        }
+        token = strtok_r(NULL, "/", &saveptr);
+    }
+
+    return count;
+}
