+                return entry->inum;
+            }
+        }
+    }
+
+    return -1;
+}
+
+int
+TraversePath(const char *pathname)
+{
+    char *components[64];
+    int ncomponents = ParsePathname(pathname, components, 64);
+    int current_inum = ROOTINODE;
+
+    for (int i = 0; i < ncomponents; i++) {
+        current_inum = FindInodeInDir(current_inum, components[i]);
+        if (current_inum < 0) {
+            return -1;
+        }
+    }
+
+    return current_inum;
+}
+
+int
+AllocateInode(int type)
+{
+    int i;
+
+    for (i = 0; i < num_inodes; i++) {
+        struct inode *inode = GetInode(i);
+        if (inode && inode->type == INODE_FREE) {
+            /* Initialize inode */
+            inode->type = type;
+            inode->nlink = 1;
+            inode->reuse = 0;
+            inode->size = 0;
+            memset(inode->direct, 0, sizeof(inode->direct));
+            inode->indirect = 0;
+            PutInode(i);
+            return i;
+        }
+    }
+
+    return -1;
+}
